  let transmissionRayLength = length(transmissionRay);
  let refractedRayExit = position_inWorld + transmissionRay;

  let ndcPos = get_projectionMatrix(cameraSID) * get_viewMatrix(cameraSID) * vec4f(refractedRayExit, 1.0);
